// One API call per active company, provider-specific URL.
const urls = {
  lever: s => `https://api.lever.co/v0/postings/${s}?mode=json`,
  greenhouse: s => `https://boards-api.greenhouse.io/v1/boards/${s}/jobs?content=true`,
  ashby: s => `https://api.ashbyhq.com/posting-api/job-board/${s}`
};
return $input.all()
  .filter(i => i.json.active && urls[i.json.ats_provider])
  .map(i => ({ json: {
    name: i.json.name,
    ats_provider: i.json.ats_provider,
    ats_slug: i.json.ats_slug,
    api_url: urls[i.json.ats_provider](i.json.ats_slug)
  }}));

// Normalize the three ATS response shapes into one, keep internships only.
const strip = h => String(h || '').replace(/&lt;/g, '<').replace(/&gt;/g, '>').replace(/&amp;/g, '&').replace(/<[^>]+>/g, ' ');
const cos = $('Build ATS API calls').all();
const out = [];
const seen = new Set();
$input.all().forEach((item, i) => {
  const co = cos[i] ? cos[i].json : {};
  const d = item.json;
  let jobs = [];
  if (co.ats_provider === 'lever' && Array.isArray(d)) {
    jobs = d.map(j => ({
      url: j.hostedUrl,
      title: j.text,
      text: [j.text, j.categories && j.categories.location, j.categories && j.categories.commitment, j.descriptionPlain, (j.lists || []).map(l => l.text + ': ' + strip(l.content)).join(' ')].filter(Boolean).join('\n')
    }));
  } else if (co.ats_provider === 'greenhouse' && d && Array.isArray(d.jobs)) {
    jobs = d.jobs.map(j => ({
      url: j.absolute_url,
      title: j.title,
      text: [j.title, j.location && j.location.name, strip(j.content)].filter(Boolean).join('\n')
    }));
  } else if (co.ats_provider === 'ashby' && d && Array.isArray(d.jobs)) {
    jobs = d.jobs.map(j => ({
      url: j.jobUrl || j.applyUrl,
      title: j.title,
      text: [j.title, j.location, j.descriptionPlain || strip(j.descriptionHtml)].filter(Boolean).join('\n')
    }));
  }
  for (const j of jobs) {
    if (!j.url || !j.title) continue;
    // \bintern\b will NOT match "international" (word boundary), by design
    if (!/\bintern(ship|s)?\b/i.test(j.title + ' ' + j.text.slice(0, 400))) continue;
    if (seen.has(j.url)) continue;
    seen.add(j.url);
    out.push({ json: {
      source: 'careers',
      source_url: j.url,
      company: co.name,
      role_hint: 'other',
      raw_text: j.text.replace(/\s+/g, ' ').trim().slice(0, 6000)
    }});
  }
});
return out;

const known = new Set(
  $('Fetch known URLs').all().map(i => i.json.source_url).filter(Boolean)
);
return $('Normalize + filter internships').all().filter(i => !known.has(i.json.source_url));

// Same extraction prompt as the Internshala workflow.
const SYSTEM = 'You extract structured data from internship job postings in India. Output ONLY a valid JSON object, no markdown fences, no commentary. If a field is not stated use null (arrays: [], booleans: false). Never guess stipend numbers. Schema: {"title":string,"company":string,"role_category":"pm"|"growth"|"analyst"|"swe"|"other","location":string|null,"city":string|null,"is_remote":boolean,"stipend_min_inr":integer|null,"stipend_max_inr":integer|null,"duration_months":number|null,"yoe_required":number,"ppo_offered":boolean,"posted_at":"YYYY-MM-DD"|null,"skills":[string],"perks":[string]}. Rules: stipend is monthly INR ("8-12k" -> min 8000 max 12000; "unpaid" -> 0; convert lakhs/year to monthly). city: one normalized Indian city (Bangalore, Mumbai, Delhi NCR, Hyderabad, Pune, Chennai, Kolkata, or the proper city name), null if remote-only. yoe_required: years of prior experience asked, 0 if none mentioned. posted_at: resolve relative dates against the given today date. skills: lowercase canonical tags (excel, sql, power bi, google analytics, figma, a/b testing, seo, communication...), exclude generic filler like "hardworking". role_category: pm=product roles, growth=marketing/growth/community, analyst=data/business/product analyst, swe=software/web/app/backend/frontend/qa/devops/ml engineering, else other.';
const today = new Date().toISOString().slice(0, 10);
return $input.all().map(item => ({ json: {
  ...item.json,
  anthropic_body: {
    model: 'claude-haiku-4-5',
    max_tokens: 1024,
    temperature: 0,
    system: SYSTEM,
    messages: [{ role: 'user', content: `Today's date: ${today}\n\nPosting URL: ${item.json.source_url}\nCompany (from registry): ${item.json.company}\nPosting text:\n---\n${item.json.raw_text}\n---` }]
  }
}}));

const reqs = $('Build Claude request').all();
const out = [];
$input.all().forEach((item, i) => {
  try {
    const txt = (item.json.content && item.json.content[0] && item.json.content[0].text) || '';
    const j = JSON.parse(txt.replace(/^```json\s*/i, '').replace(/```\s*$/, '').trim());
    const meta = reqs[i] ? reqs[i].json : {};
    out.push({ json: {
      source: 'careers',
      source_url: meta.source_url,
      raw_text: meta.raw_text,
      title: j.title,
      company: j.company || meta.company,
      role_category: ['pm','growth','analyst','swe','other'].includes(j.role_category) ? j.role_category : 'other',
      location: j.location,
      city: j.city,
      is_remote: !!j.is_remote,
      stipend_min_inr: Number.isFinite(j.stipend_min_inr) ? Math.round(j.stipend_min_inr) : null,
      stipend_max_inr: Number.isFinite(j.stipend_max_inr) ? Math.round(j.stipend_max_inr) : null,
      duration_months: j.duration_months,
      yoe_required: Number.isFinite(j.yoe_required) ? j.yoe_required : 0,
      ppo_offered: typeof j.ppo_offered === 'boolean' ? j.ppo_offered : null,
      posted_at: /^\d{4}-\d{2}-\d{2}$/.test(j.posted_at || '') ? j.posted_at : null,
      skills: Array.isArray(j.skills) ? j.skills.map(s => String(s).toLowerCase().trim()) : [],
      perks: Array.isArray(j.perks) ? j.perks : [],
      extraction_model: 'claude-haiku-4-5',
      extraction_json: j
    }});
  } catch (e) { /* skip unparseable; retried next run since URL was never inserted */ }
});
return out;
